import{_ as a,v as t,f as r,i as o}from"./chunks/framework.jfF5glnW.js";const _=JSON.parse('{"title":"Week 9 | 立创 EDA 与校庆 PCB 设计","description":"","frontmatter":{"title":"Week 9 | 立创 EDA 与校庆 PCB 设计","date":"2026-04-28T00:00:00.000Z","tags":["课程周志","PCB设计","立创EDA"],"cover":"/code2real_blog/posts/week9/shit.jpg"},"headers":[],"relativePath":"posts/week9.md","filePath":"posts/week9.md"}'),s={name:"posts/week9.md"};function i(l,e,p,n,d,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<p>第九周开始进入 PCB 设计。本周使用立创 EDA 完成西南交通大学校庆主题电路板设计，重点是熟悉从原理图到 PCB 版图的基本流程。</p><hr><img src="/code2real_blog/posts/week9/shit.jpg" alt="Week 9 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周主要学习立创 EDA 的基础操作，包括新建工程、绘制原理图、选择元件封装、生成 PCB、布线以及检查设计规则。相比前面 ESP32 的连线实验，PCB 设计要求把临时接线转化为可以制造的固定电路。</p><p>本次任务以西南交通大学校庆为主题，需要在功能电路之外加入一定的纪念性设计。也就是说，电路板既要能表达基本电气连接，又要在外形、丝印和布局上体现校庆元素。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>实践中先完成原理图部分，确认元件之间的连接关系，再为元件匹配合适封装。封装确认后进入 PCB 页面，将元件摆放到板框内，并根据连线关系进行布线。</p><p>在布局时，我没有直接把元件随意放满板面，而是先确定主要视觉区域和功能区域。校庆相关文字、标识和装饰内容放在较醒目的位置，电气元件则尽量保持连线简洁，避免布线在板面上过度交叉。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>本周最容易出问题的是封装匹配。原理图符号只说明电气关系，真正制造时还要看封装尺寸、引脚间距和焊盘位置。如果封装选错，电路在软件里看似正确，实际焊接时就会直接出问题。</p><p>另一个问题是美观和布线之间的冲突。为了保留校庆主题效果，某些区域不适合放太多走线；但如果只考虑视觉，线路又可能绕得很乱。最后只能在布局阶段反复调整，把元件位置、丝印内容和走线路径一起考虑。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>第九周让我第一次完整接触 PCB 设计流程。原理图、封装、布局、布线和规则检查之间是连续关系，前一步处理不稳，后面都会受到影响。</p><p>这次校庆电路板设计也让我认识到，PCB 不只是电路载体，它同时具有结构和表达属性。设计时既要保证电气连接可靠，也要考虑制造、焊接和最终展示效果。</p><hr><h3 id="作业" tabindex="-1">作业： <a class="header-anchor" href="#作业" aria-label="Permalink to &quot;作业：&quot;">​</a></h3><p>运用ai，设计led电子徽章☆含校庆元素☆4or5个元件的☆标注尺寸☆线条宽度1mm，拐弯必须45°要求提交两张图：PCB图和3D预览图</p><img src="/code2real_blog/posts/week9/1.png" alt="Week 9 image"><img src="/code2real_blog/posts/week9/2.png" alt="Week 9 image">',20)])])}const m=a(s,[["render",i]]);export{_ as __pageData,m as default};
